        const c2x = p2.x + Math.cos(angle2 - Math.PI / 2) * cpDist;
        const c2y = p2.y + Math.sin(angle2 - Math.PI / 2) * cpDist;

        path += ` C ${c1x} ${c1y}, ${c2x} ${c2y}, ${p2.x} ${p2.y}`;
    }

    return path + " Z";
};

