    let path = `M ${width * 0.5} ${height * 0.1}`;
    for (let i = 0; i < curves; i++) {
        const cp1x = (Math.random() * 2 - 0.5) * width;
        const cp1y = (Math.random() * 2 - 0.5) * height;
        const cp2x = (Math.random() * 2 - 0.5) * width;
        const cp2y = (Math.random() * 2 - 0.5) * height;
        const endX = (Math.random() * 1.4 - 0.2) * width;
        const endY = (Math.random() * 1.4 - 0.2) * height;
        path += ` C ${cp1x} ${cp1y}, ${cp2x} ${cp2y}, ${endX} ${endY}`;
    }
    const finalCp1x = (Math.random() * 2 - 0.5) * width;
    const finalCp1y = (Math.random() * 2 - 0.5) * height;
    const finalCp2x = (Math.random() * 2 - 0.5) * width;
    const finalCp2y = (Math.random() * 2 - 0.5) * height;
    path += ` C ${finalCp1x} ${finalCp1y}, ${finalCp2x} ${finalCp2y}, ${width * 0.5} ${height * 0.1} Z`;
    return path;
};

type PillState = 'moving' | 'offering' | 'clicked';

interface AnimatedBackgroundProps {
    mousePos: { x: number; y: number };
    onStateChange?: (state: string) => void;
}

const AnimatedBackground: React.FC<AnimatedBackgroundProps> = ({ mousePos, onStateChange }) => {
    const canvasRef = useRef<HTMLCanvasElement>(null);
    const mousePosRef = useRef(mousePos);
    const [pillState, setPillState] = useState<PillState>('moving');

    useEffect(() => {
        mousePosRef.current = mousePos;
    }, [mousePos]);

    const animationState = useRef({
        animationFrameId: 0,
        path: document.createElementNS('http://www.w3.org/2000/svg', 'path'),
        path2D: new Path2D(),
        pathLength: 0,
        progress: 0,
        speed: 1.2,
        pillPos: { x: 0, y: 0 },
        isHovered: false,
    });

    // Handle clicking the pill
    useEffect(() => {
        const handleGlobalClick = () => {
            if (animationState.current.isHovered) {
                const link = document.createElement('a');
                link.href = "https://zcxsscvheqidzvkhlnwz.supabase.co/storage/v1/object/public/Default%20image/resume.pdf";
                link.download = "Arendu_Chanda_Resume.pdf";
                link.click();
                setPillState('clicked');
                setTimeout(() => setPillState('moving'), 2000);
            }
        };
        window.addEventListener('click', handleGlobalClick);
        return () => window.removeEventListener('click', handleGlobalClick);
    }, []);

    useEffect(() => {
        onStateChange?.(pillState);
    }, [pillState, onStateChange]);

    useEffect(() => {
        const canvas = canvasRef.current;
        if (!canvas) return;
        const ctx = canvas.getContext('2d');
        if (!ctx) return;

        const state = animationState.current;

        const resizeCanvas = () => {
            canvas.width = window.innerWidth;
            canvas.height = window.innerHeight;
            const pathData = getPathData(canvas.width, canvas.height);
            state.path.setAttribute('d', pathData);
            state.path2D = new Path2D(pathData);
            state.pathLength = state.path.getTotalLength();
            state.progress = 0;
        };

        resizeCanvas();
        window.addEventListener('resize', resizeCanvas);

        const animate = (time: number) => {
            if (state.pathLength > 0) {
                ctx.clearRect(0, 0, canvas.width, canvas.height);

                // Background Path
                ctx.save();
                ctx.strokeStyle = 'rgba(241, 213, 0, 0.03)';
                ctx.lineWidth = 1;
                ctx.stroke(state.path2D);
                ctx.restore();

                const currentPoint = state.path.getPointAtLength(state.progress);
                state.pillPos = { x: currentPoint.x, y: currentPoint.y };

                const prevPointProgress = (state.progress - 2 + state.pathLength) % state.pathLength;
                const prevPoint = state.path.getPointAtLength(prevPointProgress);
                const angle = Math.atan2(currentPoint.y - prevPoint.y, currentPoint.x - prevPoint.x);

                const currentMousePos = mousePosRef.current;
                const dist = Math.hypot(currentMousePos.x - currentPoint.x, currentMousePos.y - currentPoint.y);

                const hovering = dist < 40;
                state.isHovered = hovering;

                if (hovering && pillState !== 'clicked') {
                    setPillState('offering');
                } else if (!hovering && pillState === 'offering') {
                    setPillState('moving');
                }

                if (pillState !== 'offering') {
                    state.progress = (state.progress + state.speed) % state.pathLength;
                }

                // Draw Aura if offering
                if (pillState === 'offering') {
                    ctx.save();
                    ctx.translate(currentPoint.x, currentPoint.y);
                    const pulse = Math.sin(time / 200) * 5 + 15;
                    ctx.beginPath();
                    ctx.arc(0, 0, pulse, 0, Math.PI * 2);
                    ctx.fillStyle = 'rgba(241, 213, 0, 0.1)';
                    ctx.fill();
                    ctx.restore();
                }

                // Draw Pill
                ctx.save();
                ctx.translate(currentPoint.x, currentPoint.y);
                ctx.rotate(angle);

                ctx.beginPath();
                ctx.roundRect(-15, -6, 30, 12, 6);
                ctx.fillStyle = pillState === 'clicked' ? '#4ADE80' : '#F1D500';
                ctx.fill();

                // Text inside pill if offering
                if (pillState === 'offering') {
                   ctx.rotate(-angle);
                   ctx.fillStyle = '#000';
                   ctx.font = 'bold 8px Ubuntu';
                   ctx.textAlign = 'center';
                   ctx.textBaseline = 'middle';
                   ctx.fillText('CV', 0, 0);
                }
                ctx.restore();

                // Callout bubble
                if (pillState === 'offering') {
                    ctx.save();
                    ctx.translate(currentPoint.x, currentPoint.y - 30);
                    ctx.fillStyle = 'white';
                    ctx.font = '10px Ubuntu';
                    ctx.textAlign = 'center';
                    ctx.fillText('Click to download CV', 0, 0);
                    ctx.restore();
                }
            }
            state.animationFrameId = window.requestAnimationFrame(animate);
        };

        animate(0);

        return () => {
            window.cancelAnimationFrame(state.animationFrameId);
            window.removeEventListener('resize', resizeCanvas);
        };
    }, [pillState]);

    return <canvas ref={canvasRef} className="fixed top-0 left-0 w-full h-full z-0 pointer-events-none" />;
};

