                />;
      case 'ProjectDetail':
        return <ProjectDetailPage project={view.project!} onBack={handleBack} />;
      case 'Contact':
        return <ContactPage />;
      case 'Blog':
        return <BlogPage />;
      case 'About':
      default:
        return <AboutPage onNavigate={(tab) => handleSetView(tab)} />;
    }
  };

  const cursorVariants = {
    default: { scale: 1, backgroundColor: 'rgba(241, 213, 0, 0.5)', mixBlendMode: 'normal' as const },
    hover: { scale: 1.5, backgroundColor: 'rgba(255, 255, 255, 1)', mixBlendMode: 'difference' as const },
  };

  return (
    <main 
        className="relative w-full bg-[#101010] text-white overflow-x-hidden cursor-none"
        onMouseMove={handleMouseMove}
        onMouseLeave={handleMouseLeave}
    >
      <motion.div
        className="fixed top-0 left-0 w-8 h-8 rounded-full pointer-events-none z-[9999]"
        style={{ translateX: mousePos.x - 16, translateY: mousePos.y - 16 }}
        variants={cursorVariants}
        animate={cursorVariant}
        transition={{ type: 'spring', stiffness: 500, damping: 30 }}
      />
      <AnimatedBackground mousePos={mousePos} onStateChange={setBgState} />
      <div className="relative z-10 flex min-h-screen w-full flex-col p-6 sm:p-8 md:p-16">
        <Header activeTab={view.name} setActiveTab={(tab) => handleSetView(tab)} />
        <AnimatePresence mode="wait">
          {renderPage()}
        </AnimatePresence>
        <Footer systemStatus={bgState} />
      </div>
    </main>
  );
}

