type PillState = 'moving' | 'offering' | 'clicked';

interface AnimatedBackgroundProps {
    mousePos: { x: number; y: number };
    onStateChange?: (state: string) => void;
}

const AnimatedBackground: React.FC<AnimatedBackgroundProps> = ({ mousePos, onStateChange }) => {
    const canvasRef = useRef<HTMLCanvasElement>(null);
    const mousePosRef = useRef(mousePos);
    const [pillState, setPillState] = useState<PillState>('moving');

    useEffect(() => {
        mousePosRef.current = mousePos;
    }, [mousePos]);

    const animationState = useRef({
        animationFrameId: 0,
        path: document.createElementNS('http://www.w3.org/2000/svg', 'path'),
        path2D: new Path2D(),
        pathLength: 0,
        progress: 0,
        speed: 1.5,
        isHovered: false,
    });

    useEffect(() => {
        const handleGlobalClick = () => {
            // If the pill is stopped (offering), trigger the download
            if (animationState.current.isHovered && pillState === 'offering') {
                const link = document.createElement('a');
                link.href = "https://zcxsscvheqidzvkhlnwz.supabase.co/storage/v1/object/public/Default%20image/resume.pdf";
                link.download = "Arendu_Chanda_Resume.pdf";
                link.click();
                setPillState('clicked');
                // Revert to moving after a few seconds
                setTimeout(() => setPillState('moving'), 3000);
            }
        };
        window.addEventListener('mousedown', handleGlobalClick);
        return () => window.removeEventListener('mousedown', handleGlobalClick);
    }, [pillState]);

    useEffect(() => {
        onStateChange?.(pillState);
    }, [pillState, onStateChange]);

    useEffect(() => {
        const canvas = canvasRef.current;
        if (!canvas) return;
        const ctx = canvas.getContext('2d');
        if (!ctx) return;

        const state = animationState.current;

        const resizeCanvas = () => {
            canvas.width = window.innerWidth;
            canvas.height = window.innerHeight;
            const pathData = getPathData(canvas.width, canvas.height);
            state.path.setAttribute('d', pathData);
            state.path2D = new Path2D(pathData);
            state.pathLength = state.path.getTotalLength();
            state.progress = 0;
        };

        resizeCanvas();
        window.addEventListener('resize', resizeCanvas);

        const animate = (time: number) => {
            if (state.pathLength > 0) {
                ctx.clearRect(0, 0, canvas.width, canvas.height);

                // --- 1. DRAW SOLID PATH ---
                ctx.save();
                ctx.strokeStyle = 'rgba(241, 213, 0, 0.08)';
                ctx.lineWidth = 1.2;
                ctx.stroke(state.path2D);
                ctx.restore();

                const currentPoint = state.path.getPointAtLength(state.progress);
                const prevPointProgress = (state.progress - 1 + state.pathLength) % state.pathLength;
                const prevPoint = state.path.getPointAtLength(prevPointProgress);
                const angle = Math.atan2(currentPoint.y - prevPoint.y, currentPoint.x - prevPoint.x);

                const currentMousePos = mousePosRef.current;
                const distToPill = Math.hypot(currentMousePos.x - currentPoint.x, currentMousePos.y - currentPoint.y);

                // Detection threshold for stopping the pill
                const shouldStop = distToPill < 60;
                state.isHovered = shouldStop;

                if (pillState !== 'clicked') {
                    if (shouldStop) {
                        if (pillState !== 'offering') setPillState('offering');
                    } else {
                        if (pillState === 'offering') setPillState('moving');
                        state.progress = (state.progress + state.speed) % state.pathLength;
                    }
                }

                // --- 2. DRAW PILL ---
                ctx.save();
                ctx.translate(currentPoint.x, currentPoint.y);
                ctx.rotate(angle);

                // Pulsing glow when interactive
                if (pillState === 'offering') {
                    const pulse = Math.sin(time / 200) * 4 + 14;
                    ctx.beginPath();
                    ctx.arc(0, 0, pulse, 0, Math.PI * 2);
                    ctx.fillStyle = 'rgba(241, 213, 0, 0.15)';
                    ctx.fill();
                }

                ctx.beginPath();
                ctx.roundRect(-11, -5, 22, 10, 5); // Pill dimensions

                if (pillState === 'clicked') {
                    ctx.fillStyle = '#10B981'; // Green on success
                } else if (pillState === 'offering') {
                    ctx.fillStyle = '#FFFFFF'; // White when stop
                } else {
                    ctx.fillStyle = '#F1D500'; // Standard yellow
                }
                ctx.fill();

                // Label inside pill when offering
                if (pillState === 'offering') {
                   ctx.rotate(-angle); 
                   ctx.fillStyle = '#000000';
                   ctx.font = 'bold 7px Ubuntu';
                   ctx.textAlign = 'center';
                   ctx.textBaseline = 'middle';
                   ctx.fillText('CV', 0, 0);
                }
                ctx.restore();

                // --- 3. DOWNLOAD UI (The Option) ---
                if (pillState === 'offering') {
                    ctx.save();
                    ctx.translate(currentPoint.x, currentPoint.y - 38);

                    // Main Bubble
                    ctx.fillStyle = '#F1D500';
                    ctx.beginPath();
                    ctx.roundRect(-65, -13, 130, 26, 13);
                    ctx.fill();

                    // Pointer triangle
                    ctx.beginPath();
                    ctx.moveTo(-6, 13);
                    ctx.lineTo(6, 13);
                    ctx.lineTo(0, 20);
                    ctx.fill();

                    // Bubble Text
                    ctx.fillStyle = '#101010';
                    ctx.font = 'bold 10px Ubuntu';
                    ctx.textAlign = 'center';
                    ctx.textBaseline = 'middle';
                    ctx.fillText('DOWNLOAD RESUME', 0, 0);
                    ctx.restore();
                }

                // Feedback for clicked state
                if (pillState === 'clicked') {
                    ctx.save();
                    ctx.translate(currentPoint.x, currentPoint.y - 38);
                    ctx.fillStyle = '#10B981';
                    ctx.font = 'bold 12px Ubuntu';
                    ctx.textAlign = 'center';
                    ctx.fillText('RESUME DOWNLOADED ✓', 0, 0);
                    ctx.restore();
                }
            }
            state.animationFrameId = window.requestAnimationFrame(animate);
        };

        animate(0);

        return () => {
            window.cancelAnimationFrame(state.animationFrameId);
            window.removeEventListener('resize', resizeCanvas);
        };
    }, [pillState]);

    return <canvas ref={canvasRef} className="fixed top-0 left-0 w-full h-full z-0 pointer-events-none" />;
};

