export const ContactPage: React.FC = () => {
    const [formData, setFormData] = useState({
        name: '',
        email: '',
        subject: '',
        message: '',
    });

    const [errors, setErrors] = useState<Record<string, string | null>>({});
    const [isSubmitted, setIsSubmitted] = useState(false);
    const [sendStage, setSendStage] = useState<'idle' | 'sending' | 'encrypting' | 'routing' | 'error'>('idle');
    const [sentData, setSentData] = useState<typeof formData | null>(null);
    const [copied, setCopied] = useState(false);

    const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>) => {
        const { name, value } = e.target;
        setFormData(prev => ({ ...prev, [name]: value }));
        if (errors[name]) {
            setErrors(prev => ({ ...prev, [name]: null }));
        }
    };

    const validate = () => {
        const newErrors: Record<string, string | null> = {};
        if (!formData.name.trim()) newErrors.name = "Name is required.";
        if (!formData.email.trim()) {
            newErrors.email = "Email is required.";
        } else if (!/\S+@\S+\.\S+/.test(formData.email)) {
            newErrors.email = "Email address is invalid.";
        }
        if (!formData.subject.trim()) newErrors.subject = "Subject is required.";
        if (!formData.message.trim()) newErrors.message = "Message is required.";

        return newErrors;
    };

    const handleSubmit = async (e: React.FormEvent<HTMLFormElement>) => {
        e.preventDefault();
        const validationErrors = validate();
        setErrors(validationErrors);

        if (Object.keys(validationErrors).length === 0) {
            setSendStage('sending');
            const dataToTransmit = { ...formData };

            try {
                // Visual delay for flair/branding
                await new Promise(resolve => setTimeout(resolve, 600));
                setSendStage('encrypting');

                const response = await fetch('https://kyla-postfebrile-jannette.ngrok-free.dev/v1/insert_portfolio_mail_inbox', {
                    method: 'POST',
                    headers: {
                        'Content-Type': 'application/json',
                    },
                    body: JSON.stringify(dataToTransmit),
                });

                if (!response.ok) throw new Error('Failed to send message');

                setSendStage('routing');
                await new Promise(resolve => setTimeout(resolve, 800));

                setSentData(dataToTransmit);
                setIsSubmitted(true);
                setSendStage('idle');
                setFormData({ name: '', email: '', subject: '', message: '' });
            } catch (err) {
                console.error("Submission error:", err);
                setSendStage('error');
                setTimeout(() => setSendStage('idle'), 3000);
                setErrors({ general: "Unable to transmit message. Please try again later or email directly." });
            }
        }
    };

    const copyToClipboard = () => {
        navigator.clipboard.writeText('arenduchanda1997@gmail.com');
        setCopied(true);
        setTimeout(() => setCopied(false), 2000);
    };

    const getButtonText = () => {
        switch(sendStage) {
            case 'sending': return 'Initiating Session...';
            case 'encrypting': return 'Encrypting Payload...';
            case 'routing': return 'Routing to Server...';
            case 'error': return 'Transmission Failed';
            default: return 'Send Message';
        }
    };

    return (
        <motion.div
            key="contact"
